import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { DashboardStats } from '../types';
import api from '../utils/api';
import { useAuth } from '../hooks/useAuth';

function getGreeting() {
  const h = new Date().getHours();
  if (h >= 5  && h < 12) return 'Good morning';
  if (h >= 12 && h < 17) return 'Good afternoon';
  if (h >= 17 && h < 21) return 'Good evening';
  return 'Good night';
}

export default function Dashboard() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [stats, setStats] = useState<DashboardStats|null>(null);
  const [loading, setLoading] = useState(true);
  const isStaff = user?.userType === 'user';

  useEffect(() => {
    api.get('/borrows/stats')
      .then(r => { setStats(r.data.data); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  if (loading) return (
    <div style={{ display:'flex', alignItems:'center', justifyContent:'center', height:'100vh' }}>
      <div style={{
        width: 24, height: 24,
        border: '2px solid var(--border)',
        borderTopColor: 'var(--accent)',
        borderRadius: '50%',
        animation: 'spin .8s linear infinite'
      }}/>
    </div>
  );

  const cards = [
    { label: 'Total books',     value: stats?.totalBooks    ?? 0, hint: 'in catalogue' },
    { label: 'Active members',  value: stats?.totalMembers  ?? 0, hint: 'enrolled' },
    { label: 'Books out',       value: stats?.activeBorrows ?? 0, hint: 'currently borrowed' },
    { label: 'Overdue',         value: stats?.overdueBorrows?? 0, hint: 'past due date', tone: (stats?.overdueBorrows ?? 0) > 0 ? 'danger' : undefined },
  ];

  const roleDisplay =
    user?.role === 'librarian'         ? 'Head Librarian' :
    user?.role === 'library_assistant' ? 'Asst. Librarian' :
    user?.role === 'student'           ? 'Student' :
    'Staff Member';

  return (
    <div className="page-enter" style={{ padding: '28px 36px', maxWidth: 1280, margin: '0 auto' }}>

      {/* ─── Header ─── */}
      <div style={{ display:'flex', alignItems:'flex-start', justifyContent:'space-between', gap:16, marginBottom: 28 }}>
        <div>
          <p className="eyebrow" style={{ marginBottom: 8 }}>
            {new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
          </p>
          <h1 style={{ fontSize: 26, fontWeight: 700, color: 'var(--text)', letterSpacing: '-0.5px' }}>
            {getGreeting()}, {user?.name?.split(' ')[0]}
          </h1>
          <p style={{ fontSize: 13.5, color: 'var(--text-muted)', marginTop: 4 }}>
            Here's what's happening at the library today.
          </p>
        </div>

        <div style={{
          background: 'var(--bg2)', border: '1px solid var(--border)',
          borderRadius: 10, padding: '10px 14px', minWidth: 180, textAlign: 'right'
        }}>
          <div className="eyebrow" style={{ fontSize: 10 }}>Signed in as</div>
          <div style={{ fontSize: 14, fontWeight: 600, color: 'var(--text)', marginTop: 2 }}>{roleDisplay}</div>
          {user?.member_id && (
            <div className="mono" style={{ fontSize: 11.5, color: 'var(--text-muted)', marginTop: 2 }}>
              {user.member_id}
            </div>
          )}
        </div>
      </div>

      {/* ─── Alerts ─── */}
      {isStaff && stats && stats.pendingMembers > 0 && (
        <AlertRow tone="warning"
          title={`${stats.pendingMembers} account${stats.pendingMembers>1?'s':''} waiting for approval`}
          hint="Review pending members"
          onClick={() => navigate('/members?status=pending')} />
      )}
      {isStaff && stats && stats.pendingRequests > 0 && (
        <AlertRow tone="accent"
          title={`${stats.pendingRequests} borrow request${stats.pendingRequests>1?'s':''} pending`}
          hint="Review and approve"
          onClick={() => navigate('/requests')} />
      )}

      {stats && <>
        {/* ─── Stat cards ─── */}
        <div style={{ display:'grid', gridTemplateColumns:'repeat(4, 1fr)', gap: 12, marginBottom: 24 }}>
          {cards.map(c => (
            <div key={c.label} className="card card-pad card-hover" style={{ padding: '18px 18px 16px' }}>
              <div style={{ fontSize: 12.5, color: 'var(--text-muted)', fontWeight: 500 }}>{c.label}</div>
              <div style={{
                fontSize: 30, fontWeight: 700, color: c.tone === 'danger' ? 'var(--danger)' : 'var(--text)',
                letterSpacing: '-0.8px', marginTop: 6, lineHeight: 1.1
              }}>
                {c.value.toLocaleString()}
              </div>
              <div style={{ fontSize: 11.5, color: 'var(--text-subtle)', marginTop: 4 }}>{c.hint}</div>
            </div>
          ))}
        </div>

        {/* ─── Two columns ─── */}
        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap: 16 }}>

          <Panel title="Recent borrows" badge={`${stats.recentBorrows.length} latest`}>
            {stats.recentBorrows.length ? (
              <div>
                {stats.recentBorrows.map((b: any) => (
                  <div key={b.id} style={{
                    display:'flex', alignItems:'center', gap:12,
                    padding:'10px 4px',
                    borderTop:'1px solid var(--border)'
                  }}>
                    <span className="dot" style={{
                      background: b.status === 'returned' ? 'var(--success)'
                                : b.status === 'overdue'  ? 'var(--danger)'
                                : 'var(--accent)'
                    }} />
                    <div style={{ flex:1, minWidth:0 }}>
                      <div style={{ fontSize:13, fontWeight:500, color:'var(--text)', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>
                        {b.title}
                      </div>
                      <div style={{ fontSize:11.5, color:'var(--text-muted)', marginTop:1 }}>
                        {b.member_name}
                      </div>
                    </div>
                    <span className={
                      b.status === 'returned' ? 'badge badge-success'
                      : b.status === 'overdue' ? 'badge badge-danger'
                      : 'badge badge-accent'
                    }>{b.status}</span>
                  </div>
                ))}
              </div>
            ) : <Empty>No borrows yet.</Empty>}
          </Panel>

          <Panel title="Popular books" badge="Top 5">
            {stats.popularBooks.length ? (
              <div>
                {stats.popularBooks.map((b: any, i: number) => (
                  <div key={b.title} style={{
                    display:'flex', alignItems:'center', gap:12,
                    padding:'10px 4px',
                    borderTop:'1px solid var(--border)'
                  }}>
                    <div className="mono" style={{
                      width: 22, textAlign: 'center',
                      fontSize: 12, fontWeight: 600,
                      color: 'var(--text-muted)'
                    }}>{i + 1}</div>
                    <div style={{ flex:1, minWidth:0 }}>
                      <div style={{ fontSize:13, fontWeight:500, color:'var(--text)', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>
                        {b.title}
                      </div>
                      <div style={{ fontSize:11.5, color:'var(--text-muted)', marginTop:1 }}>
                        {b.author}
                      </div>
                    </div>
                    <div className="mono" style={{ fontSize: 12.5, fontWeight: 600, color: 'var(--text)' }}>
                      {b.borrow_count}×
                    </div>
                  </div>
                ))}
              </div>
            ) : <Empty>No data yet.</Empty>}
          </Panel>
        </div>
      </>}
    </div>
  );
}

function Panel({ title, badge, children }: { title: string; badge?: string; children: React.ReactNode }) {
  return (
    <div className="card" style={{ padding: '16px 18px' }}>
      <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', paddingBottom: 10 }}>
        <h3 style={{ fontSize: 14, fontWeight: 600, color: 'var(--text)' }}>{title}</h3>
        {badge && <span style={{ fontSize: 11.5, color: 'var(--text-muted)' }}>{badge}</span>}
      </div>
      {children}
    </div>
  );
}

function AlertRow({ tone, title, hint, onClick }: { tone: 'warning' | 'accent'; title: string; hint: string; onClick: () => void }) {
  const colors = tone === 'warning'
    ? { bg: 'var(--warning-soft)', border: 'rgba(217,119,6,0.25)', dot: 'var(--warning)', text: 'var(--warning)' }
    : { bg: 'var(--accent-soft)', border: 'var(--accent-soft-2)', dot: 'var(--accent)', text: 'var(--accent-text)' };
  return (
    <div onClick={onClick} role="button"
      style={{
        background: colors.bg, border: `1px solid ${colors.border}`,
        borderRadius: 10, padding: '11px 14px', marginBottom: 12,
        display: 'flex', alignItems: 'center', gap: 12, cursor: 'pointer'
      }}>
      <span className="dot" style={{ background: colors.dot, animation: 'pulse-soft 2s ease-in-out infinite' }} />
      <div style={{ flex: 1 }}>
        <div style={{ fontSize: 13, fontWeight: 600, color: colors.text }}>{title}</div>
        <div style={{ fontSize: 12, color: 'var(--text-muted)', marginTop: 1 }}>{hint}</div>
      </div>
      <span style={{ fontSize: 12.5, color: colors.text, fontWeight: 500 }}>View →</span>
    </div>
  );
}

function Empty({ children }: { children: React.ReactNode }) {
  return (
    <div style={{
      padding: '28px 0', textAlign: 'center',
      fontSize: 13, color: 'var(--text-muted)',
      borderTop: '1px solid var(--border)'
    }}>{children}</div>
  );
}
